Part.Source:
&SoNumeroCNPJ = RetornaSoNumeros.Udp(&PesCnpj)
&SoNumeroCPF = RetornaSoNumeros.Udp(&PesCPF)

&NomeXML = &SdtConfiguracoesPasta.PastaNFretorno+trim(&SoNumeroCNPJ)+'-ret-cons-cad.xml'

&File.Source = &NomeXML
If &File.Exists()

	&LeituraXml.Open(&NomeXML)
	&LeituraXml.Readtype(1, 'retConsCad')
	&LeituraXml.Read()

	Do While (&LeituraXml.Name <> 'retConsCad' and &LeituraXml.Name <> '')
		Do Case

			//## INFORMAÇÕES DA CONSULTA ##\\

			//## Status da consulta. ##\\
			Case &LeituraXml.Name = 'cStat'
				&NfeAutSts = &LeituraXml.Value

				//## Descrição do Status da consulta. ##\\
			Case &LeituraXml.Name = 'xMotivo'
				&NfeAutMsg = &LeituraXml.Value

				//## Sigla da UF consultada. ##\\	
			Case &LeituraXml.Name = 'UF'
				&NfeConsUF = &LeituraXml.Value

				//## CNPJ consultado. ##\\
			Case &LeituraXml.Name = 'CNPJ'
				&NfeConsCNPJ = &LeituraXml.Value

				//## CPF consultado. ##\\
			Case &LeituraXml.Name = 'CPF'
				&NfeConsCPF = &LeituraXml.Value

				//## Data e hora de processamento da consulta. ##\\
			Case &LeituraXml.Name = 'dhCons'
				&NfeConsDH = &LeituraXml.Value

				//## Código da UF que atendeu a solicitação. ##\\
			Case &LeituraXml.Name = 'cUF'
				&NfeConsCUF = &LeituraXml.Value

				//#############################\\

				//## INFORMAÇÕES DO CONTIRBUINTE ##\\

				//## Inscrição estadual do contribuinte. ##\\
			Case &LeituraXml.Name = 'IE'
				&NfeRetIE = &LeituraXml.Value

				//## CNPJ do contribuinte. ##\\
			Case &LeituraXml.Name = 'CNPJ'
				&NfeRetCNPJ = &LeituraXml.Value

				//## CPF em caso de pessoa física com IE. ##\\
			Case &LeituraXml.Name = 'CPF'
				&NfeRetCNAE = &LeituraXml.Value

				//## UF de localização do contribuinte. ##\\
			Case &LeituraXml.Name = 'UF'
				&NfeRetUF = &LeituraXml.Value

				//## Situação do contribuinte: 0 - não habilitado; 1 - habilitado. ##\\
			Case &LeituraXml.Name = 'cSit'
				&NfeRetCSit = &LeituraXml.Value

				//## Indicador de contribuinte credenciado a emitir NF-e. 0 - Não credenciado para emissão da NF-e; 1 - Credenciado; 2 - Credenciado com obrigatoriedade para todas operações; 3 - Credenciado com obrigatoriedade parcial; 4 – a SEFAZ não fornece a informação. ##\\
			Case &LeituraXml.Name = 'indCredNFe'
				&NfeRetindCredNFe = &LeituraXml.Value

				//## Indicador de contribuinte credenciado a emitir CT-e. 0 - Não credenciado para emissão da CT-e; 1 - Credenciado; 2 - Credenciado com obrigatoriedade para todas operações; 3 - Credenciado com obrigatoriedade parcial; 4 – a SEFAZ não fornece a informação. ##\\
			Case &LeituraXml.Name = 'indCredCTe'
				&NfeindCredCTe = &LeituraXml.Value

				//## Razão Social ou nome do Contribuite. ##\\
			Case &LeituraXml.Name = 'xNome'
				&PesRaz = &LeituraXml.Value

				//## Nome Fantasia. ##\\
			Case &LeituraXml.Name = 'xFant'
				&PesFan = &LeituraXml.Value

				//## Regime de Apuração do ICMS do Contribuinte. ##\\
			Case &LeituraXml.Name = 'xRegApur'
				&NfeRetRegApur = &LeituraXml.Value

				//## CNAE principal do contribuinte. ##\\
			Case &LeituraXml.Name = 'CNAE'
				&NfeRetCNAE = &LeituraXml.Value

				//## Data de Início da Atividade do Contribuinte. ##\\
			Case &LeituraXml.Name = 'dIniAtiv'
				&NfeRetdIniAtiv = &LeituraXml.Name

				//## Data da última modificação da situação cadastral do contribuinte. ##\\
			Case &LeituraXml.Name = 'dUltSit'
				&NfeRetdUltSit = &LeituraXml.Value

				//## Data de ocorrência da baixa do contribuinte. ##\\
			Case &LeituraXml.Name = 'dBaixa'
				&NfeRetBaixa = &LeituraXml.Value

				//## IE atual (em caso de IE antiga consultada) ##\\
			Case &LeituraXml.Name = 'IEAtual'
				&PesInsEst = &LeituraXml.Value
				If &PesInsEst.IsEmpty()
					&PesInsEst = &NfeRetIE
				EndIf

				//#################################\\

				//## INFORMAÇÕES DE ENDEREÇO ##\\

				//## Nome do Logradouro. ##\\
			Case &LeituraXml.Name = 'xLgr'
				&PesLog = &LeituraXml.Value

				//## Número. ##\\
			Case &LeituraXml.Name = 'nro'
				&PesNro = &LeituraXml.Value

				//## Complemento. ##\\
			Case &LeituraXml.Name = 'xCpl'
				&PesCompl = &LeituraXml.Value

				//## Bairro. ##\\
			Case &LeituraXml.Name = 'xBairro'
				&PesBai = &LeituraXml.Value

				//## código da Cidade ##\\
			Case &LeituraXml.Name = 'cMun'
				&CidIBGE.FromString(&LeituraXml.Value)
				Do 'CidadeIBGE'

				//## Nome do município. ##\\
			Case &LeituraXml.Name = 'xMun'
				&PesCidNom = &LeituraXml.Value
				Do 'CidadeIBGE'
				//## Código do CEP. ##\\
			Case &LeituraXml.Name = 'CEP'
				&PesCEP = &LeituraXml.Value

				//#############################\\	

		EndCase

		&LeituraXml.Read()

	EndDo

	&LeituraXml.Close()

	If &PesInsEst.IsEmpty()
		&PesInsEst = &NfeRetIE
	EndIF

	If &NfeAutSts = '111'

		&Mensagem = 'Consulta Realizada com Sucesso!'
		&Existe = True

	Else

		If not &NfeAutSts.IsEmpty()
			&Existe = True
			Do case 

				Case &NfeAutSts = '112'
					&Mensagem = 'Consulta Realizada com Sucesso! Existe mais de um estabelecimento para o argumento pesquisado.'

					//## ERROS na Verificação do Certificado de Transmissão ##\\

					//## Tentou realizar a consulta utilizando um Certificado Digital inválido. ##\\
				Case &NfeAutSts = '280' //## Efetue a reinstalação ou substitua o Certificado Digital, e reenvie a NF-e. ##\\
					&Mensagem = 'Rejeição: Certificado Transmissor inválido.'

					//## Tentou realizar a consulta utilizando um Certificado Digital, fora do prazo de validade. ##\\
				Case &NfeAutSts = '281' //## Atualize o certificado digital com uma data válida e realize uma nova emissão de NF-e. ##\\
					&Mensagem = 'Rejeição: Certificado Transmissor vencido.'

					//## Tentou realizar a consulta utilizando um Certificado Digital sem vinculação do CNPJ do emitente. ##\\
				Case &NfeAutSts = '282' //## É necessário validar se o certificado digital utilizado está vinculado ao CNPJ da empresa. ##\\
					&Mensagem = 'Rejeição: Certificado Transmissor sem CNPJ.'

					//## Tentou realizar a consulta utilizando um Certificado Digital, com a Cadeia de Certificação desatualizada. ##\\
				Case &NfeAutSts = '283'	//## Provavelmente será necessária a troca do Certificado Digital. ##\\	
					&Mensagem = 'Rejeição: Certificado Transmissor - erro Cadeia de Certificação.'

					//## Tentou realizar a consulta utilizando um Certificado Digital revogado. ##\\
				Case &NfeAutSts = '284' //## É necessário utilizar um outro certificado digital válido para a emissão de um novo documento. ##\\
					&Mensagem = 'Rejeição: Certificado Transmissor revogado.'

					//## Tentou realizar a consulta utilizando um Certificado Digital incompatível com a raiz certificadora ICP-Brasil. ##\\
				Case &NfeAutSts = '285' //## A utilização de um novo certificado corrige a situação. ##\\
					&Mensagem = 'Rejeição: Certificado Transmissor difere ICP-Brasil.'

					//## A assinatura está na Lista de Certificados Revogados (LCR). ##\\
				Case &NfeAutSts = '286' //## Normalmente basta aguardar alguns instantes e enviar o documento novamente. ##\\
					&Mensagem = 'Rejeição: Certificado Transmissor erro no acesso a LCR.'

					//########################################################\\

					//## ERROS na Validação das Regras de Negócio da Consulta Cadastro, feita pela SEFAZ ##\\

					//## Caso a consulta seja feita por CNPJ ##\\

					//## Tentou realizar a consulta e o CNPJ do Emitente não está autorizado para emissão de documento fiscal na SEFAZ. ##\\
				Case &NfeAutSts = '257'//## É necessário verificar a situação cadastral da empresa emitente. ##\\
					&Mensagem = 'Rejeição: Solicitante não habilitado para emissão da NF-e.'

					//## Tentou realizar a consulta e o CNPJ do Contribuinte apresenta inconsistência nos dados, como por exemplo erro no dígito de controle , ou zeros. ##\\
				Case &NfeAutSts = '258' //## É necessário verificar a situação cadastral do contribuinte. ##\\
					&Mensagem = 'Rejeição: CNPJ da CONSULTA	inválido.'

					//## Tentou realizar a consulta e o CNPJ do Contribuinte de ICMS não inscrito em uma UF. ##\\
				Case &NfeAutSts = '259' //## É necessário verificar a situação cadastral do contribuinte. ##\\
					&Mensagem = 'Rejeição: CNPJ da CONSULTA não cadastrado como contribuinte na UF.'

					//#########################################\\

					//## Caso a consulta seja feita por Inscrição Estadual ##\\

					//## Tentou realizar a consulta e a Inscrição Estadual do contribuinte apresenta inconsistência nos dados, como por exemplo erro no dígito de controle , ou zeros ##\\
				Case &NfeAutSts = '260' //## É necessário verificar a situação cadastral do contribuinte. ##\\
					&Mensagem = 'Rejeição: IE da CONSULTA inválida.'

					//## Tentou realizar a consulta e a Inscrição Estadual do contribuinte não está cadastrado na Unidade Federativa (UF) consultada. ##\\
				Case &NfeAutSts = '261' //## É necessário, verificar a situação cadastral do contribuinte, considerando a UF de cadastro da Inscrição Estadual informada. ##\\
					&Mensagem = 'Rejeição: IE da CONSULTA não cadastrada como contribuinte na UF.'

					//#######################################################\\

					//## Caso a consulta seja feita por CPF ##\\

					//## Tentou realizar a consulta através do CPF do contribuinte, onde a UF não disponibiliza esse tipo de consulta. ##\\
				Case &NfeAutSts = '262' //## Essa rejeição indica que não é possível utilizar consultas por CPF na UF informada. Não tem como resolver, senta e chora. ##\\
					&Mensagem = 'Rejeição: UF não fornece consulta por CPF.'

					//## Tentou realizar a consulta através de um CPF do contribuinte inconsistente (ex. erro no dígito de controle). ##\\
				Case &NfeAutSts = '263' //## É necessário verificar a situação cadastral do contribuinte. ##\\
					&Mensagem = 'Rejeição: CPF da consulta inválido.'

					//## Tentou realizar a consulta através do CPF do contribuinte, que não corresponde a UF consultada. ##\\
				Case &NfeAutSts = '264' //## É necessário, verificar a situação cadastral do contribuinte, considerando a UF de cadastro do CPF. ##\\
					&Mensagem = 'Rejeição: CPF da consulta não cadastrado como contribuinte na UF.'

					//########################################\\

					//## Tentou realizar a consulta com uma sigla da UF diferente da UF do Web Service. ##\\
				Case &NfeAutSts = '265' //## É necessário, verificar se a sigla da UF informado confere com o Web Service consultado. ##\\
					&Mensagem = 'Rejeição: Sigla da UF da consulta difere da UF do Web Service.'

			EndCase

		EndIf

	EndIf

EndIF


Sub 'CidadeIBGE'

	For each Order EmpCod,CidCod
		Where EmpCod = &EmpCod
		Where CidIBGE = &CidIBGE when &CidIBGE > 0
		Where CidNom = UPPER(&PesCidNom) WHEN &CidIBGE  <= 0
		&CidCod = CidCod
		Exit
	EndFor

EndSub
